// Normalize incoming transcript
const body = $input.first().json.body || $input.first().json;
const transcript = body.transcript || body.text || '';
const accountId = body.account_id || 'UNKNOWN';
const source = body.source || 'demo';

return [{
  json: {
    account_id: accountId,
    transcript: transcript,
    source: source,
    received_at: new Date().toISOString()
  }
}];

// Normalize onboarding input (transcript or form JSON)
const body = $input.first().json.body || $input.first().json;
const accountId = body.account_id || 'UNKNOWN';
const inputType = body.input_type || 'transcript';
const data = body.data || body.transcript || JSON.stringify(body.form || {});

return [{
  json: {
    account_id: accountId,
    onboarding_data: data,
    input_type: inputType,
    received_at: new Date().toISOString()
  }
}];

