// Parse LLM extraction response and build account memo v1
const response = $input.first().json;
const content = response.content[0].text;

let memo = {};
try {
  const clean = content.replace(/```json\s*/g, '').replace(/```/g, '').trim();
  memo = JSON.parse(clean);
} catch(e) {
  memo = { parse_error: e.message, raw: content };
}

const accountId = $('Normalize Input').first().json.account_id;
memo.account_id = accountId;
memo.version = 'v1';
memo.source = 'demo_call';
memo.generated_at = new Date().toISOString().split('T')[0];

return [{ json: memo }];

// Generate Retell Agent Spec from memo
const memo = $input.first().json;
const bh = memo.business_hours || {};
const pricing = memo.pricing || {};
const transfer = memo.call_transfer_rules || {};

const spec = {
  agent_name: `Clara - ${memo.company_name || 'Unknown'}`,
  version: 'v1',
  source: 'demo_call',
  account_id: memo.account_id,
  generated_at: new Date().toISOString().split('T')[0],
  voice_style: {
    tone: 'professional, warm, efficient',
    language: 'en-US',
    persona: `Clara, assistant for ${memo.company_name}`
  },
  key_variables: {
    company_name: memo.company_name,
    owner_name: memo.contact_name,
    business_hours: `${(bh.days||[]).join(', ')}, ${bh.start} to ${bh.end}`,
    timezone: bh.timezone,
    notification_email: memo.notification_email,
    transfer_number: transfer.transfer_number || 'PENDING'
  },
  call_transfer_protocol: {
    trigger: 'Caller requests owner or emergency dispatch',
    transfer_number: transfer.transfer_number || 'PENDING',
    announce_before_transfer: 'Please hold while I connect you.',
    on_transfer_fail: transfer.transfer_fail_message || 'Unable to connect. Your details have been noted.'
  },
  system_prompt: '[GENERATED BY SEPARATE LLM CALL - see pipeline_a_extract.py]',
  tool_invocation_placeholders: {
    transfer_call: 'Trigger when caller should be connected to owner.',
    send_notification: 'Send call summary to notification email and SMS after each call.'
  }
};

return [{ json: { memo, spec } }];
